solutions.python:
class Solution:
    def solve(self, users):
        return sorted(set(user[0] for user in users))

if __name__ == '__main__':
    users = [[1, 'John', 'john@example.com'], [3, 'Jane', 'jane@example.com'], [5, 'Bob', 'bob@example.com']]
    solution = Solution()
    result = solution.solve(users)
    print(result)
